def _make_hash(attrs):
    attrs = tuple(
        a
        for a in attrs
        if a.hash is True or (a.hash is None and a.cmp is True)
    )

    # We cache generated hash method for same kind attribute.
    key = tuple((a.type, a.name) for a in attrs)
    if key in _hash_cache:
        return _hash_cache[key]
    def hash_func(self):
        return hash(tuple(getattr(self, a.name) for a in attrs))
    _hash_cache[key] = hash_func
    return hash_func

