    def _rewrite(self, req, start_response):
        path = req.path_info
        if req.query_string:
            path += '?' + req.query_string
        parts = urlparse.urlparse(path)
        headers = req.headers
        scheme = parts.scheme
        netloc = parts.netloc
        if not scheme:
            scheme = 'http'
        if not netloc:
            netloc = headers.get('Host', '')
        new_url = scheme + '://' + netloc + parts.path
        if parts.query:
            new_url += '?' + parts.query
        return new_url

