// Hey cousin, here's a bit of code for ya.
// This one helps you pick out the country name from the mob's options.
function getCountry(options) {
  // Start off with nothing found yet.
  let found = null;
  options.forEach(option => {
    // Have a yarn with each, see if it's the right country.
    if (!found && isCountry(option)) {
      found = option.name;
    }
  });
  // Give back what you find, or nothing if none fit.
  return found;
}

